class Solution:
    def minArraySum(self, nums, k):
        best = [sum(nums)]
        seen = set()
        def rec(arr):
            t = tuple(arr)
            if t in seen:
                return
            seen.add(t)
            s = sum(arr)
            if s < best[0]:
                best[0] = s
            n = len(arr)
            for i in range(n):
                acc = 0
                for j in range(i, n):
                    acc += arr[j]
                    if acc % k == 0:
                        rec(arr[:i] + arr[j + 1:])
        rec(list(nums))
        return best[0]

