class Solution:
    def minArraySum(self, nums, k):
        INF = float('inf')
        prev = 0
        bestres = {0: 0}
        pre = 0
        for x in nums:
            pre = (pre + x) % k
            cur = prev + x
            if pre in bestres and bestres[pre] < cur:
                cur = bestres[pre]
            if pre not in bestres or cur < bestres[pre]:
                bestres[pre] = cur
            prev = cur
        return prev

