var minArraySum = function(nums, k) {
    let prev = 0;
    const bestres = new Map();
    bestres.set(0, 0);
    let pre = 0;
    for (const x of nums) {
        pre = (pre + x) % k;
        let cur = prev + x;
        if (bestres.has(pre) && bestres.get(pre) < cur) cur = bestres.get(pre);
        if (!bestres.has(pre) || cur < bestres.get(pre)) bestres.set(pre, cur);
        prev = cur;
    }
    return prev;
};
